import { useState } from "react";

function InputBox({ onSend, disabled }) {
    const [text, setText] = useState("");

    const handleSend = () => {
        if (!text.trim() || disabled) return;
        onSend(text);
        setText("");
    };

    return (
        <div
            style={{
                padding: "16px",
                borderTop: "1px solid #e5e7eb",
                background: "white",
            }}
        >
            <div
                style={{
                    display: "flex",
                    alignItems: "center",
                    maxWidth: "900px",
                    margin: "0 auto",
                }}
            >
                <input
                    value={text}
                    disabled={disabled}
                    onChange={(e) => setText(e.target.value)}
                    placeholder={
                        disabled ? "AI is responding…" : "Send a message"
                    }
                    style={{
                        flex: 1,
                        padding: "14px",
                        borderRadius: "12px",
                        border: "1px solid #d1d5db",
                        fontSize: "16px",
                        outline: "none",
                    }}
                    onKeyDown={(e) => e.key === "Enter" && handleSend()}
                />
                <button
                    onClick={handleSend}
                    disabled={disabled}
                    style={{
                        marginLeft: "12px",
                        padding: "14px 18px",
                        borderRadius: "12px",
                        border: "none",
                        backgroundColor: "#2563eb",
                        color: "white",
                        fontSize: "16px",
                        cursor: "pointer",
                        opacity: disabled ? 0.6 : 1,
                    }}
                >
                    ➤
                </button>
            </div>
        </div>
    );
}

export default InputBox;
